data.冒泡法排序816#冒泡法排序(8.16):
利用冒泡法做数组内数字的大小排序。
我们先设置一个数组，并写两个函数来控制这个数组的输入和输出。
#include<stdio.h> void print(int *score) { while(*score!=-1) printf("%d ",*score++);/*当score不是-1的时候，我们让指针向后移位的同时输出这个指针对应的数组的量*/ } void read(int *score) { do scanf("%d",score);//读入数组元素 while(*score++!=-1);//判断指针score对应元素的是否是-1的同时指针向后移位 } int main(void) { int score[40]= {0,};//40是题目指定的数组最大长度，其中我们以不被算入的-1作为结束 read(score); print(score); return 0; } 接下来考虑冒泡法排序。冒泡法的原理是通过每次比较前后两个数字的大小来实现整个排序过程。所以我们循环的结束条件应该是检验数组内的数字是否已经排列整齐。如果我们每次循环都做这样的检验，未免显得过于麻烦。所以我们换种方式考虑：设置一个计数器，每次进行交换的时候让计数器+1(当然每次循环都需要初始化为0)，若循环到最后一次的时候已经不再需要做交换，那么计数器就是0，也即说明我们的交换已经做完了，可以离开循环了。
void mpf(int *score) {//以指针形式传入数组 int all=-1,temp=0; while(score[++all]!=-1) ;//all自增同时检验是否all是否到达-1的位置 for(int cnt=1; cnt>0;) {/*判断结束的条件是该次循环已经没有再对数组做修改，即操作次数(cnt)为0*/ cnt=0;//cnt最为每次循环的计数器，循环每次初始化为0 for(int test=0; test<all-1; test++) {//test最大只能到all-2 if(score[test]>score[test+1]) { temp=score[test]; score[test]=score[test+1]; score[test+1]=temp; cnt++; }//在需要的时候进行交换，并且记录操作次数 } } } //...read(score);//main函数内 mpf(score); //print(score);... 这样程序就完成了。完整代码：
#include<stdio.h> void mpf(int *score) { int all=-1,temp=0; while(score[++all]!=-1) ; for(int cnt=1; cnt>0;) { cnt=0; for(int test=0; test<all-1; test++) { if(score[test]>score[test+1]) { temp=score[test]; score[test]=score[test+1]; score[test+1]=temp; cnt++; } } } } void print(int *score) { while(*score!=-1) printf("%d ",*score++); } void read(int *score) { do scanf("%d",score); while(*score++!=-1); } int main(void) { int score[40]= {0,}; read(score); mpf(score); print(score); return 0; } 测试：
1 3 2 4 5 9 7 6 26 13 29 333 22 52 42 88 -1//输入 1 2 3 4 5 6 7 9 13 22 26 29 42 52 88 333//输出

data.利用黎曼和求积分96#利用黎曼和求积分(9.6):
简单来说即利用梯形法求函数和数轴围成的面积。根据定积分的定义有 $$ \int_a^b f(x){\rm d}x=\lim_{N\rightarrow\infty}\frac{b-a}{N}\sum_{k=1}^{N}f\left(\xi_k\right),\xi_k\in\left(\frac{b-a}{N}(k-1),\frac{b-a}{N}k\right) $$ ,由于$\xi_k$的选取是任意的，我们直接选取单边，于是积分公式即 $$ \int_a^b f(x){\rm d}x=\lim_{N\rightarrow\infty}\frac{b-a}{N}\sum_{k=1}^{N}f\left(\frac{b-a}{N}k\right) $$ 根据上述公式实现代码如下。
#include <stdio.h> #define N 100000//细分多少份 float Integrate(float(*f)(float),float a,float b) { float c=0; for (int i=1; i<=N; i++) c+=f(i*(b-a)/N);//求和部分 return c*(b-a)/N; } float function1(float x) {//题目要求的两个待积分函数 return 1+x*x; } float function2(float x) { return x/(1+x*x); } float (*f[2])(float)= {function1,function2};//函数指针的数组 int main(void) { printf("%f,%f",Integrate(f[0],0.0,1.0),Integrate(f[1],0.0,3.0)); return 0; } 输出为
1.333351,1.151306 我们可以直接计算两个积分为 $$ \int_0^1 1+x^2 {\rm d}x=\frac{4}{3},\int_0^3\frac{x}{1+x^2}{\rm d}x=\frac{1}{2}\ln 10 $$ 可见结果精度还是比较高的。

data.斐波那契数列#斐波那契数列:
简单实现斐波那契数列是很简单的。
#include<stdio.h> long fbnq(long init){ return init==1?1:init==2?1:fbnq(init-1)+fbnq(init-2);//初始两个1，接下来是一个递推 } int main(void){ for(long i=1;i<=45;i++) printf("fbnq(%d)=%d\n",i,fbnq(i)); return 0; } 但是我们运行就会发现时常非常长，该代码效率极低。为什么？我们做递归的时候，例如我们计算fbnq(40)，我们把前39个斐波那契数全又算了一遍。这是一件非常不合理的事情。在计算第45个就已经很吃力了，所以我们仅仅欣赏代码的简洁性。不妨来计算一下这个代码的时间复杂度。
我们将调用一次函数作为所谓的一次运算。例如我们输入fbnq(n)，那么下一步运算就是需要计算fbnq(n-1)+fbnq(n-2)。注意！这里我们的fbnq(n-1)依然是一个独立的整体，是需要重新计算的。我们认定计算次数为${\rm Cnt}(n)$，那么就得到递推关系 $$ {\rm Cnt}(n)={\rm Cnt}(n-1)+{\rm Cnt}(n-2) $$ 我们还知道n为1或者2的时候我们只需要调用一次函数，所以实际上计算次数和斐波那契数的结果是一样的！如果不进行直接数学运算的话，可以看看待会输出的结果，让计算机进行这么多运算来得到结果显然是愚蠢的做法。如果我们知道斐波那契数列的通项公式的话，那么运算的时间复杂度就是$O\left(\exp\left(n\right)\right)$。我们刚才说运算到45已经很吃力了，我们根据fbnq(45)=1134903170,在运算这个结果的时候我们反复调用了这个函数11 3490 3170次！
我们利用数组改进如下。
#include<stdio.h> #define len 700 #define ws 200 int main(void) { int a[len][ws]= {{1,},{1,}};//初始化两个1 for(int cnt=2; cnt<len; cnt++) { for(int init=0; init<ws; init++) { a[cnt][init]=a[cnt-1][init]+a[cnt-2][init];//对每一位递推 } for(int jw=0; jw<ws-1; jw++) { a[cnt][jw+1]+=a[cnt][jw]/10; a[cnt][jw]%=10; }//实现进位 } for(int cnt=0; cnt<len; cnt++) { printf("fbnq(%d)=",cnt+1);//输出 for(int init=ws-1,codeblock=0;init>=0;init--) { if(a[cnt][init]!=0||codeblock==1){//遇到第一个非0数开始持续输出至首位 printf("%d",a[cnt][init]); codeblock=1; } } printf("\n"); } return 0; } 这样我们实现了高精度运算。并且利用数组储存我们每一个结果，这样我们进行递推的时候就只需要调用之前的运算结果，这样就极大的简化了我们的运算。我们选取部分输出如下：
fbnq(290)=1806885656323799249738933639586633513160792578781310139745345 fbnq(291)=2923602405716568564338475449381171413803636207598822186175234 fbnq(292)=4730488062040367814077409088967804926964428786380132325920579 fbnq(293)=7654090467756936378415884538348976340768064993978954512095813 fbnq(294)=12384578529797304192493293627316781267732493780359086838016392 fbnq(295)=20038668997554240570909178165665757608500558774338041350112205 fbnq(296)=32423247527351544763402471792982538876233052554697128188128597 fbnq(297)=52461916524905785334311649958648296484733611329035169538240802 fbnq(298)=84885164052257330097714121751630835360966663883732297726369399 fbnq(299)=137347080577163115432025771710279131845700275212767467264610201 fbnq(300)=222232244629420445529739893461909967206666939096499764990979600 \\290~300之间的结果 fbnq(700)=87470814955752846203978413017571327342367240967697381074230432592527501911 290377655628227150878427331693193369109193672330777527943718169105124275 书接上文，让电脑执行这个数量的运行次数显然不合理。那么利用数组进行运算，由于我们已经将数字存下来了，(在这里我们对位执行操作不计算入运行次数，因为我们如果使用int之类的类型来计算，计算机内部也会执行位运算)所以每计算一个斐波那契数都只需要运行一次。该程序运行起来已经非常迅速。至于再次优化，那么又是压位高精，或者更高级的有关数论的优化算法。例如高精乘法可以从$O(n^2)$利用FFT优化到$O(n \log n)$，这又是很大的进步。(对数增长的速度远远低于幂函数，我们有以下结论：对于$\forall \alpha>0$, $$ \lim_{x\rightarrow+\infty}\frac{\log x}{x^\alpha}=0 $$ }

data.最大公因数的实现#最大公因数的实现:
采用辗转相除法，并将其内置为函数。本次写法为前导式。 #include <stdio.h> int gcd(int a, int b); //前导式函数引语，指明最大公因数函数的函数的输入输出格式。 int main(void) { int a = 0, b = 0; scanf("%d %d", &a, &b); printf("%d\n", gcd(a, b)); return 0; } int gcd(int a, int b) { int d = 1, cnt = 1; if (a <= b) { d = a, a = b, b = d; } //判断两数大小，保持大的在前。 for (cnt = 1; b > 0; cnt++) { d = b, b = a % b, a = d; } return a; } 这里有一个易错点：在for循环语句中我们的判断条件是可以继续执行的条件而不是结束条件，所以gcd函数中的for条件应该是$b>0$，而不是等于0.
这样的代码在实现需要的功能已经是没有问题了，那么如果我们还需要多次输入以及美化这个函数，我们可以进行如下修改。
#include <stdio.h> int gcd(int a, int b); int main(void) { int a = 0, b = 0, n = 0, judge = 1; char K = '1'; for (n = 0; judge; n++) { printf("输入两个需要得出最大公因数的正整数（两个数中间用空格隔开）："); scanf("%d %d", &a, &b); printf("%d\n", gcd(a, b)); printf("请问您还需要判断下一组数据吗？回答Y或者N："); scanf(" %c", &K); judge = K == 'Y' ? 1 : 0; } return 0; } int gcd(int a, int b) { int d = 1, cnt = 1; if (a <= b) { d = a, a = b, b = d; } for (cnt = 1; b > 0; cnt++) { d = b, b = a % b, a = d; } return a; } 请注意这里的易错点：我们输入两个数后按了回车，这个回车键是会被scanf扫描进char的，因为char规定回车键也是字符的一种。所以我们在scanf中提前插入空格来保证这个回车不会产生影响。
上述程序中我们利用了for循环的特性来写这样一个判断语句。如果用户输入Y，我们认定judge的值为1，即条件为真，因此输入Y意味着我们可以进行下一轮测试。此外我们还可以利用if，并且直接省略for中的判断语句（但是分号不能丢），采用continue和break来判断。
for (n = 0;; n++) { //直接将其替换上面的代码对应行即可。 printf("输入两个需要得出最小公因数的正整数（两个数中间用空格隔开）："); scanf("%d %d", &a, &b); printf("%d\n", gcd(a, b)); printf("请问您还需要判断下一组数据吗？回答Y或者N："); scanf(" %c", &K); if (K == 'Y') continue; else break; } break和continue起到了for语句第二条的作用，实质上这样写便和while语句没有区别了。最后我们甚至可以不使用循环语句，仅仅利用goto。因此我们省去了几个不需要的变量。
int main(void) { int a = 0, b = 0, c = 0; char K = '1'; A: printf("输入两个需要得出最小公因数的正整数（两个数中间用空格隔开）："); scanf("%d %d", &a, &b); printf("%d\n", gcd(a, b)); printf("请问您还需要判断下一组数据吗？回答Y或者N："); scanf(" %c", &K); if (K == 'Y') goto A; else goto B; B: return 0; } 下一步我们考虑对gcd函数的进一步简化。我们有没有必要先判断ab的大小进行交换呢？不如这样考虑，如果ab不进行交换会发生什么？a获得了b的值，b获得了a$%$b的值。注意，由于b比a大，所以实际上a$%$b还是a！这样我们就做了一次交换。所以代码中对ab的大小判断实际上是可以删掉的。
int gcd(int a, int b) { int d = 1, cnt; for (cnt = 1; b > 0; cnt++) { d = b, b = a % b, a = d; } return a; } 我们在函数中写了一个自降的循环，这是可以的。但是我们实际上在函数的调用中天然就可以写出循环，也就是函数自循环。例如我们在函数的返回值中继续调用gcd，那么它便又返回gcd函数中了。所以我们利用三目运算符和函数自降简化如下：
int gcd(int a, int b) { return b ? gcd(b, a % b): a; /*b是0吗？不是的话(请注意只写一个b表示布尔运算，即非0为真，0为假)就返回gcd(b,a%b)，是就返回a(程序结束)*/ } 另外我们换一种自循环的递降算法也一样可以大大简洁代码
#include<stdio.h> int gcd(int a,int b){ return a>b?gcd(a-b,b):a<b?gcd(a,b-a):a;/*若a>b则返回gcd(a-b,b),若a<b则返回gcd(a,b-a),若都不然(即两数相等)返回a,程序结束*/} int main(){ int a=0,b=0; scanf("%d %d",&a,&b); printf("%d",gcd(a,b)); return 0; } 最后给出效率最低的方式：穷举法。我们从较小的数开始向下穷举，直到发现第一个可以被两数同时整除的数字。
#include<stdio.h> int gcd(int a,int b){ int c; for(c= a>b?b:a;a%c!=0||b%c!=0;c--); return c; } int main(void) { int a,b; scanf("%d %d",&a,&b); printf("%d",gcd(a,b)); return 0; }

data.素数和#素数和:
**问题：**我们认为2是第一个素数，3是第二个素数，5是第三个素数，依次类推。 现在，给定两个整数n和m，$0<n\leq m<200$，你的程序要计算第n个素数到第m个素数之间所有的素数的和，包括第n个素数和第m个素数。
#include <stdio.h> int main(void) { int n = 0, m = 0, cnt = 0, zs = 0, i = 0, judge = 0, sum = 0; scanf("%d %d", &n, &m); for (i = 2; cnt <= m - 1; i++) { zs = 1; for (judge = 2; judge < i; judge++) { if (i % judge == 0) { //判断是否是素数 zs = 0; } } cnt = zs ? cnt + 1 : cnt; //是素数则计数器自增 sum+=(zs && (cnt >= n))*i; //若是素数且在所需要的区间内算入总和 } printf("%d", sum); return 0; } 分为几个步骤：判断是否是素数，是素数则计数器自增，若是素数且在所需要的区间内算入总和。其中判断素数可以写为一个函数，虽然在本题中的意义并不大。
int zspd(int i) { int judge = 1, zs = 1; for (judge = 2; judge < i; judge++) { if (i % judge == 0) { zs = 0; } } return zs; } 此时原代码只需要去掉main中不需要的变量，并将原本判断素数的循环改为zs=zspd(i);即可。

data.非对称矩阵转置115#非对称矩阵转置(11.5):
实现矩阵转置。下面的代码使用了一维数组当作二维数组进行动态内存分配。
#include<stdio.h> #include<stdlib.h>//使用calloc和free函数需要调用 void Transpose(int *a,int *at,int m,int n) {//该转置即将a的内容写入at for(int cnt=0; cnt<m; cnt++) { for(int cntt=0; cntt<n; cntt++) { at[cntt*m+cnt]=a[cnt*n+cntt]; } } } void read(int *a,int m,int n) {//读入a for(int cnt=0; cnt<m; cnt++) { for(int cntt=0; cntt<n; cntt++) { scanf("%d",&a[cnt*n+cntt]); } } } void print(int *at,int m,int n) {//打印at for(int cntt=0; cntt<n; cntt++) { for(int cnt=0; cnt<m; cnt++) { printf("%d ",at[cntt*m+cnt]); } printf("\n"); } } int main(void) { int m,n,*a=NULL,*at=NULL; scanf("%d %d",&m,&n); a=calloc(m*n,sizeof(int)); at=calloc(n*m,sizeof(int));//动态内存分配 read(a,m,n); Transpose(a,at,m,n); print(at,m,n); free(a); free(at);//释放内存 return 0; } 输出如下(Example)
3 5//矩阵大小 2 3 4 5 6 6 5 4 3 2 3 3 7 8 1//初始矩阵 2 6 3 3 5 3 4 4 7 5 3 8 6 2 1//转置后的矩阵 若仿造上一题的做法，那么代码可以是
#include <stdio.h> void Swap(int *a, int *b) { int const t = *a; *a = *b; *b = t; } #define N 10 #define M 10 void transpose_1(int a[][N], int at[][M], int m, int n) { for (int i = 0; i < m; i++) { for (int j = 0; j < n; j++) { at[j][i] = a[i][j]; } } } void transpose_2(int (*a)[N], int (*at)[M], int m, int n) { for (int i = 0; i < m; i++) { for (int j = 0; j < n; j++) { at[j][i] = a[i][j]; } } } void transpose_3(int *a, int *at, int m, int n) { for (int i = 0; i < m; i++) { for (int j = 0; j < n; j++) { *(at + j*M + i) = *(a + i*N + j);/*与上一题不同的是这题直接对赋值，所以我们考虑指针*/ } } } void input(int a[][N], int m, int n) { for (int i = 0; i < m; i++) { for (int j = 0; j < n; j++) { scanf("%d", &(a[i][j])); } } } void output(int a[][M], int m, int n) { for (int i = 0; i < m; i++) { for (int j = 0; j < n; j++) { printf("%3d", a[i][j]); } printf("\n"); } printf("\n"); } int main() { int a[M][N], at[M][N], m, n; scanf("%d %d", &m, &n); input(a, m, n); transpose_1(a, at, m, n); output(at, n, m); transpose_2(a, at, m, n); output(at, n, m); transpose_3(*a, *at, m, n); output(at, n, m); return 0; }
